const parseJsonValue = (value: unknown): { ok: boolean; value: unknown } => {
  if (value !== null && typeof value === "object") return { ok: true, value };
  if (typeof value !== "string") return { ok: false, value: null };
  const text = value.trim();
  if (!text || text.startsWith("```")) return { ok: false, value: null };
  try { return { ok: true, value: JSON.parse(text) as unknown }; }
  catch { return { ok: false, value: null }; }
};
const isRecord = (value: unknown): value is Record<string, unknown> =>
  !!value && typeof value === "object" && !Array.isArray(value);
const sameJson = (left: unknown, right: unknown): boolean =>
  JSON.stringify(left) === JSON.stringify(right);
const valueType = (value: unknown): string => {
  if (value === null) return "null";
  if (Array.isArray(value)) return "array";
  if (Number.isInteger(value)) return "integer";
  return typeof value;
};
const validateSchema = (value: unknown, schema: unknown): boolean => {
  if (!isRecord(schema)) return true;
  if (Array.isArray(schema.allOf) && !schema.allOf.every((item) => validateSchema(value, item))) return false;
  if (Array.isArray(schema.anyOf) && !schema.anyOf.some((item) => validateSchema(value, item))) return false;
  if (Array.isArray(schema.oneOf) && schema.oneOf.filter((item) => validateSchema(value, item)).length !== 1) return false;
  if (Array.isArray(schema.enum) && !schema.enum.some((item) => sameJson(item, value))) return false;
  if (Object.prototype.hasOwnProperty.call(schema, "const") && !sameJson(schema.const, value)) return false;
  const allowedTypes = Array.isArray(schema.type) ? schema.type : typeof schema.type === "string" ? [schema.type] : [];
  if (allowedTypes.length > 0) {
    const actual = valueType(value);
    if (!allowedTypes.some((expected) => expected === actual || (expected === "number" && (actual === "number" || actual === "integer")))) return false;
  }
  const properties = isRecord(schema.properties) ? schema.properties : null;
  const required = Array.isArray(schema.required) ? schema.required.map(String) : [];
  if (properties || required.length > 0) {
    if (!isRecord(value)) return false;
    if (required.some((name) => !Object.prototype.hasOwnProperty.call(value, name))) return false;
    if (properties) {
      for (const [name, childSchema] of Object.entries(properties)) {
        if (Object.prototype.hasOwnProperty.call(value, name) && !validateSchema(value[name], childSchema)) return false;
      }
      if (schema.additionalProperties === false && Object.keys(value).some((name) => !Object.prototype.hasOwnProperty.call(properties, name))) return false;
    }
  }
  if (Object.prototype.hasOwnProperty.call(schema, "items")) {
    if (!Array.isArray(value) || !value.every((item) => validateSchema(item, schema.items))) return false;
  }
  return true;
};
const validateTemplate = (value: unknown, template: unknown): boolean => {
  if (Array.isArray(template)) {
    return Array.isArray(value) && (template.length === 0 || value.every((item) => validateTemplate(item, template[0])));
  }
  if (isRecord(template)) {
    if (!isRecord(value) || Object.keys(template).length === 0) return false;
    return Object.entries(template).every(([name, child]) =>
      Object.prototype.hasOwnProperty.call(value, name) && validateTemplate(value[name], child)
    );
  }
  if (template === null) return value === null;
  return typeof value === typeof template;
};
const zero = (reason: string) => ({
  setLocals: {
    reward_should_score: false,
    validated_decision: null,
    format_validation_error: reason,
    reward: 0,
    scalar_reward: 0,
    carried_output: "0",
  },
});
const rawObservation = ctx.state.agent_latest_observation;
if (rawObservation === null || rawObservation === undefined || (typeof rawObservation === "string" && !rawObservation.trim())) {
  return zero("agent_latest_observation is empty");
}
const observation = parseJsonValue(rawObservation);
if (!observation.ok) return zero("agent_latest_observation is not one unwrapped JSON value");
const format = parseJsonValue(ctx.state.final_output_format);
if (!format.ok || (isRecord(format.value) && Object.keys(format.value).length === 0)) {
  return zero("final_output_format is unavailable");
}
const schemaKeys = new Set(["$schema", "type", "properties", "required", "items", "allOf", "anyOf", "oneOf", "enum", "const"]);
const isSchema = isRecord(format.value) && Object.keys(format.value).some((key) => schemaKeys.has(key));
const valid = isSchema
  ? validateSchema(observation.value, format.value)
  : validateTemplate(observation.value, format.value);
if (!valid) return zero("agent_latest_observation does not match final_output_format");
return {
  setLocals: {
    reward_should_score: true,
    validated_decision: observation.value,
    format_validation_error: "",
  },
};

const asRecord = (value: unknown): Record<string, unknown> => {
  if (value && typeof value === "object" && !Array.isArray(value)) return value as Record<string, unknown>;
  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value) as unknown;
      return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed as Record<string, unknown> : {};
    } catch { return {}; }
  }
  return {};
};
const parseCsvLine = (line: string): string[] => {
  const cells: string[] = [];
  let cell = "";
  let quoted = false;
  for (let index = 0; index < line.length; index += 1) {
    const character = line[index];
    if (character === '"') {
      if (quoted && line[index + 1] === '"') { cell += '"'; index += 1; }
      else quoted = !quoted;
    } else if (character === "," && !quoted) { cells.push(cell); cell = ""; }
    else cell += character;
  }
  cells.push(cell);
  return cells;
};
const trajectoryRow = asRecord(ctx.state.selected_price_trajectory);
const trajectory = asRecord(trajectoryRow.trajectory);
const files = Array.isArray(trajectory.files) ? trajectory.files.map(asRecord) : [];
const csvText = String(files.find((file) => String(file.name ?? "").toLowerCase().endsWith(".csv"))?.content ?? files[0]?.content ?? "");
const lines = csvText.split(/\r?\n/).filter((line) => line.trim());
const headers = lines.length > 0 ? parseCsvLine(lines[0]).map((value) => value.trim().toLowerCase()) : [];
const rows = lines.slice(1).flatMap((line) => {
  const cells = parseCsvLine(line);
  const read = (names: string[]) => {
    const index = headers.findIndex((header) => names.includes(header));
    return index >= 0 ? cells[index] : "";
  };
  const date = read(["date"]);
  const close = Number(read(["close", "adj close", "adjusted close"]));
  const high = Number(read(["high"]));
  const low = Number(read(["low"]));
  return /^20\d{2}-\d{2}-\d{2}$/.test(date) && Number.isFinite(close)
    ? [{ date, close, high: Number.isFinite(high) ? high : close, low: Number.isFinite(low) ? low : close }]
    : [];
}).sort((left, right) => left.date.localeCompare(right.date));
const requestedStart = String(trajectoryRow.start_date ?? trajectory.start_date ?? rows[0]?.date ?? "").slice(0, 10);
const startTime = Date.parse(requestedStart + "T00:00:00Z");
const endTime = Number.isFinite(startTime) ? startTime + 30 * 24 * 60 * 60 * 1000 : Number.NaN;
const windowRows = Number.isFinite(endTime)
  ? rows.filter((row) => {
      const time = Date.parse(row.date + "T00:00:00Z");
      return time >= startTime && time <= endTime;
    })
  : [];
let peak = windowRows[0]?.close ?? 0;
let maxDrawdown = 0;
for (const row of windowRows) {
  peak = Math.max(peak, row.close);
  if (peak > 0) maxDrawdown = Math.min(maxDrawdown, (row.close - peak) / peak);
}
const startClose = windowRows[0]?.close ?? 0;
const endClose = windowRows.at(-1)?.close ?? 0;
const available = windowRows.length >= 2 && startClose > 0;
const priceAction = available
  ? {
      ticker: String(trajectoryRow.ticker ?? trajectory.ticker ?? ""),
      start_date: windowRows[0].date,
      end_date: windowRows.at(-1)?.date ?? "",
      calendar_day_horizon: 30,
      trading_days: windowRows.length,
      start_close: startClose,
      end_close: endClose,
      return_pct: ((endClose - startClose) / startClose) * 100,
      max_drawdown_pct: maxDrawdown * 100,
      highest_price: Math.max(...windowRows.map((row) => row.high)),
      lowest_price: Math.min(...windowRows.map((row) => row.low)),
      daily_price_action: windowRows,
    }
  : {};
return {
  setLocals: {
    future_price_action_available: available,
    future_price_action_30d: priceAction,
  },
};

const priceAction = ctx.locals.future_price_action_30d;
const returnPct = priceAction && typeof priceAction === "object" && !Array.isArray(priceAction)
  ? Number((priceAction as Record<string, unknown>).return_pct)
  : Number.NaN;
const reward = Number.isFinite(returnPct) ? returnPct : 0;
return {
  setLocals: {
    reward,
    scalar_reward: reward,
    carried_output: String(reward),
  },
};

const raw = ctx.locals.carried_output;
const matched = typeof raw === "string"
  ? raw.trim().match(/-?\d+(?:\.\d+)?/i)?.[0]
  : undefined;
const candidate = typeof raw === "number"
  ? raw
  : Number(matched ?? raw ?? 0);
const reward = Number.isFinite(candidate) ? candidate : 0;
return {
  setLocals: {
    reward,
    scalar_reward: reward,
    carried_output: String(reward),
  },
};
